import{_ as t,Z as e,P as d,g as p,k as l,m as i}from"./chunks/framework.Dp5g00Bf.js";const m=JSON.parse('{"title":"查看ubuntu指定服务路径","description":"","frontmatter":{},"headers":[],"relativePath":"views/2-软件📲/系统操作/查看ubuntu指定服务路径/index.md","filePath":"views/2-软件📲/系统操作/查看ubuntu指定服务路径/index.md","lastUpdated":1778952601000}'),o={name:"views/2-软件📲/系统操作/查看ubuntu指定服务路径/index.md"};function h(r,s,c,u,g,k){const a=e("NolebaseGitContributors"),n=e("NolebaseGitChangelog");return d(),p("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778952601000"},[s[0]||(s[0]=l('<h1 id="查看ubuntu指定服务路径" tabindex="-1">查看ubuntu指定服务路径 <a class="header-anchor" href="#查看ubuntu指定服务路径" aria-label="Permalink to &quot;查看ubuntu指定服务路径&quot;">​</a></h1><p>由于ubuntu是纯命令行，我们自己部署了的服务，很多时候，过一段时间就会忘记，但是只要我们还记得服务名称叫啥其实就能找到，我以nginx为例，方法如下:</p><h3 id="_1-使用-which-或-whereis-命令-最快" tabindex="-1">1. 使用 <code>which</code> 或 <code>whereis</code> 命令（最快） <a class="header-anchor" href="#_1-使用-which-或-whereis-命令-最快" aria-label="Permalink to &quot;1. 使用 `which` 或 `whereis` 命令（最快）&quot;">​</a></h3><p>如果你已经将 <code>nginx</code> 添加到了系统的环境变量中（可以直接在任意目录下输入 <code>nginx</code> 运行），这两个命令能直接秒出结果。</p><p>打开终端，输入：</p><div class="language-Bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><em>或者：</em></p><div class="language-Bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">whereis</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p><strong>输出示例：</strong> <code>/usr/local/bin/nginx</code> 或者是你存放它的具体路径。如果没有任何输出，说明它没有在系统的环境变量中。 <img src="https://img.webis.top/storage/uploads/202605/16/Pasted%20image%2020260516212953.png?wpSHSrdUHm" alt="Pasted image 20260516212953.png"></p></blockquote><hr><h3 id="_2-使用-find-命令全局搜索-最彻底" tabindex="-1">2. 使用 <code>find</code> 命令全局搜索（最彻底） <a class="header-anchor" href="#_2-使用-find-命令全局搜索-最彻底" aria-label="Permalink to &quot;2. 使用 `find` 命令全局搜索（最彻底）&quot;">​</a></h3><p>如果你忘记了把它解压到了哪里，可以直接在整个系统中搜索名为 <code>nginx</code> 的文件。</p><p>输入以下命令（需要 <code>sudo</code> 权限以搜索系统目录）：</p><div class="language-Bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;nginx&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><p><code>/</code> 代表从根目录开始全局搜索。</p></li><li><p><code>2&gt;/dev/null</code> 的作用是过滤掉没有权限访问某些文件夹的报错提示，让结果更干净。</p></li><li><p><strong>注意：</strong> 这可能会输出两个结果，一个是 <code>nginx</code> <strong>可执行二进制文件</strong>，另一个可能是 <code>nginx.ini</code> 或 <code>nginx.toml</code> <strong>配置文件</strong>。</p></li></ul><hr><h3 id="_3-查看-systemd-服务文件-如果是开机自启" tabindex="-1">3. 查看 Systemd 服务文件（如果是开机自启） <a class="header-anchor" href="#_3-查看-systemd-服务文件-如果是开机自启" aria-label="Permalink to &quot;3. 查看 Systemd 服务文件（如果是开机自启）&quot;">​</a></h3><p>如果你把 <code>nginx</code> 配置成了开机自启的服务，可以通过查看服务配置文件来找到它的本体和配置文件的位置。</p><p>运行以下命令查看服务状态：</p><div class="language-Bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在输出的信息中，找到 <strong><code>ExecStart=</code></strong> 开头的那一行：</p><ul><li><p><code>ExecStart=/path/to/nginx -c /path/to/nginx.toml</code></p></li><li><p>这里的 <code>/path/to/nginx</code> 就是它的<strong>绝对路径</strong>。</p></li></ul><p>如果服务没运行，也可以直接查看它的 service 文件内容：</p><div class="language-Bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/systemd/system/nginx.service</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>同样在 <code>ExecStart</code> 后面就能看到具体的路径。</p><hr><h3 id="_4-通过正在运行的进程查看" tabindex="-1">4. 通过正在运行的进程查看 <a class="header-anchor" href="#_4-通过正在运行的进程查看" aria-label="Permalink to &quot;4. 通过正在运行的进程查看&quot;">​</a></h3><p>如果你的 <code>nginx</code> 当前正在后台运行，可以通过进程查看到它的启动路径：</p><div class="language-Bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ef</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在输出的结果中，除了最后的 <code>grep nginx</code> 这一行，前面那行展示的就是正在运行的 <code>nginx</code> 完整的启动命令和路径。</p>',30)),i(a),i(n)])}const F=t(o,[["render",h]]);export{m as __pageData,F as default};
